# A/B testing tone: measuring CSAT and escalation rate by tone variant

import random
from dataclasses import dataclass, field
from typing import Callable


@dataclass
class ToneExperiment:
    name: str
    persona_config: PersonaConfig
    csat_scores: list[float] = field(default_factory=list)
    escalation_count: int = 0
    total_interactions: int = 0

    def record(self, csat: Optional[float], escalated: bool) -> None:
        self.total_interactions += 1
        if csat is not None:
            self.csat_scores.append(csat)
        if escalated:
            self.escalation_count += 1

    @property
    def mean_csat(self) -> float:
        return sum(self.csat_scores) / len(self.csat_scores) if self.csat_scores else 0.0

    @property
    def escalation_rate(self) -> float:
        return self.escalation_count / self.total_interactions if self.total_interactions else 0.0

    def summary(self) -> str:
        return (
            f"Experiment: {self.name}\n"
            f"  Interactions: {self.total_interactions}\n"
            f"  Mean CSAT: {self.mean_csat:.2f}\n"
            f"  Escalation rate: {self.escalation_rate:.1%}\n"
        )


def run_tone_ab_test(
    variants: list[ToneExperiment],
    run_interaction: Callable[[PersonaConfig, str], tuple[float, bool]],
    test_inputs: list[str],
) -> ToneExperiment:
    """
    Route each test input to a randomly selected variant,
    collect CSAT and escalation rate, return the winning variant.
    """
    for user_message in test_inputs:
        variant = random.choice(variants)
        csat, escalated = run_interaction(variant.persona_config, user_message)
        variant.record(csat, escalated)

    for variant in variants:
        print(variant.summary())

    winner = max(variants, key=lambda v: v.mean_csat - v.escalation_rate * 2)
    print(f"Winner: {winner.name}")
    return winner
